function positionGuidance(p,w){var q=Number(p.qty||0),pr=Number(w.price||0),pmc=Number(p.pmc||0),pl=(pr-pmc)*q,move=Number(w.move||0),under=pr<pmc;var recovery=under?'Recovery plan: niente mediazione automatica; attendere stabilizzazione e recupero sopra PMC '+pmc+' oppure ridurre esposizione su rimbalzo.':'Recovery plan: posizione sopra PMC; proteggi il capitale e non aumentare size se la forza relativa peggiora.';var exit=under?'Exit strategy: vendere 25-50% se perde ulteriore forza relativa; mantenere solo se recupera con mercato favorevole.':'Exit strategy: trailing stop e presa parziale se il momentum si esaurisce; mantenere finche prezzo e forza relativa restano costruttivi.';if(C(p.t)==='LITE')recovery='Recovery plan: LITE e una posizione di recupero; non mediare, usa solo forza reale da market.json per ridurre o ruotare verso leader.';if(C(p.t)==='MRVL')recovery='Recovery plan: MRVL va gestita contro PMC e forza relativa; hold solo se resta sopra area PMC e non diventa weak nel ranking.';if(move<-1)exit+=' Segnale weak attivo: alza la priorita di riduzione rischio.';return{pl:pl,recovery:recovery,exit:exit}}
function portfolio(){var st=profile(),tot=Number(st.totalCapital||0),trade=Number(st.tradingCapital||0);shell('Portfolio','<div class="card"><h3>Profilo capitale salvato localmente</h3><div class="grid"><label>Capitale libero<input data-capital-profile="freeCash" type="number" step="0.01" value="'+esc(st.freeCash)+'"></label><label>Capitale trading<input data-capital-profile="tradingCapital" type="number" step="0.01" value="'+esc(st.tradingCapital)+'"></label></div><p class="muted">Capitale libero condiviso con Home, Radar, Quick Analyze ed Exit. Le posizioni sono modificabili; P/L, pesi, recovery plan ed exit strategy vengono calcolati dalla quote corrente in data/market.json.</p></div>'+(s.portfolio.map(function(p,i){var t=C(p.t),w=quoteFromMarket(t),found=!!w,fields='<div class="grid"><label>Ticker<input data-p="'+i+'" data-k="t" value="'+esc(t)+'"></label><label>Quantity<input data-p="'+i+'" data-k="qty" type="number" value="'+esc(p.qty)+'"></label><label>PMC<input data-p="'+i+'" data-k="pmc" type="number" step="0.01" value="'+esc(p.pmc)+'"></label>';if(found){var g=positionGuidance(p,w),value=Number(p.qty||0)*Number(w.price||0),plPct=Number(p.pmc||0)?((Number(w.price||0)-Number(p.pmc||0))/Number(p.pmc||0))*100:0,distPmc=plPct,wtTot=tot?value/tot*100:0,wtTrade=trade?value/trade*100:0;return'<div class="card"><div class="head"><h2>'+esc(t)+'</h2><button class="danger" data-action="removePortfolio" data-i="'+i+'">X</button></div><p><b>'+esc(w.name||t)+'</b> '+quoteBadge(w)+'</p>'+fields+'<div class="metric"><small>Live price</small>'+w.price+'</div><div class="metric"><small>P/L €</small>'+us(g.pl)+'</div><div class="metric"><small>P/L %</small>'+pc(plPct)+'</div><div class="metric"><small>Peso capitale totale</small>'+pc(wtTot)+'</div><div class="metric"><small>Peso capitale trading</small>'+pc(wtTrade)+'</div><div class="metric"><small>Distanza dal PMC</small>'+pc(distPmc)+'</div><div class="metric"><small>Move</small>'+pc(w.move)+'</div></div><div class="card"><h3>Recovery plan</h3><p>'+esc(g.recovery)+'</p><h3>Exit strategy</h3><p>'+esc(g.exit)+'</p><label>Note personali<textarea data-p="'+i+'" data-k="plan">'+esc(p.plan||'')+'</textarea></label></div></div>'}return'<div class="card"><div class="head"><h2>'+esc(t)+'</h2><button class="danger" data-action="removePortfolio" data-i="'+i+'">X</button></div>'+fields+'</div><p class="bad">Ticker not found in current market snapshot</p></div>'}).join('')||'<div class="card">Nessuna posizione.</div>'));$$('[data-p]').forEach(function(e){e.onchange=function(){var n=Number(e.getAttribute('data-p')),k=e.getAttribute('data-k');s.portfolio[n][k]=(k==='qty'||k==='pmc')?Number(e.value):(k==='t'?C(e.value):e.value);repair();portfolio()}});$$('[data-capital-profile]').forEach(function(e){var sync=function(){var k=e.getAttribute('data-capital-profile');s.capitalProfile[k]=Number(e.value||0);save()};e.oninput=sync;e.onchange=function(){sync();portfolio()}})}
function radar(){var list=radarList(),st=profile(),shown=list.slice(0,80),must={AMD:1,MU:1,LSCC:1};list.forEach(function(x){if(must[x.t]&&!shown.some(function(y){return y.t===x.t}))shown.push(x)});shell('Expanded Radar','<div class="card"><h2>'+list.length+' setup ordinati</h2><p class="muted">Radar con soli ticker reali; ID interni e quote fallback esclusi. Sizing vincolato da free cash come massimo hard, capitale trading come base rischio e riskPct come perdita massima.</p><div class="grid"><div class="metric"><small>Profilo capitale salvato localmente</small>'+eu(st.freeCash)+'</div><div class="metric"><small>Free cash hard max</small>'+eu(st.freeCash)+'</div><div class="metric"><small>Risk base</small>'+eu(st.tradingCapital)+'</div><div class="metric"><small>Risk per trade</small>'+pc(st.riskPct)+'</div></div></div>'+shown.map(card).join(''))}
function watch(){shell('Watchlist','<div class="card"><h2>Watchlist manuale</h2></div>'+s.watch.map(function(w,i){return'<div class="card"><input data-w="'+i+'" data-k="t" value="'+esc(C(w.t))+'"><input data-w="'+i+'" data-k="name" value="'+esc(w.name||'')+'"><input data-w="'+i+'" data-k="sector" value="'+esc(w.sector||'')+'"><input data-w="'+i+'" data-k="price" value="'+(w.price||0)+'"><input data-w="'+i+'" data-k="move" value="'+(w.move||0)+'"><p>'+quoteBadge(w)+'</p><button class="danger" data-action="removeWatch" data-i="'+i+'">Elimina</button></div>'}).join(''));$$('input[data-w]').forEach(function(e){e.onchange=function(){var n=Number(e.getAttribute('data-w')),k=e.getAttribute('data-k');s.watch[n][k]=(k==='price'||k==='move')?Number(e.value):(k==='t'?C(e.value):e.value);repair();watch()}})}
function marketLookup(t){t=C(t);var m=normalizeMarket(s.market||{}),all=[].concat(m.quotes||[],m.radar||[]);for(var i=0;i<all.length;i++){if(C(all[i].ticker||all[i].t||all[i].symbol)===t)return Object.assign({event:'quick analyze market.json'},all[i])}return null}
function quick(){shell('Quick Analyze','<div class="card"><input id="qt" placeholder="Ticker"><input id="qm" placeholder="Move %"><input id="qs" placeholder="Settore"><button id="qa">Analizza</button><div id="qr"></div></div>');$('#qa').onclick=function(){var t=C($('#qt').value),found=marketLookup(t),x=found||{t:t,sector:$('#qs').value||'Manual',price:100,move:Number(String($('#qm').value||0).replace(',','.')),event:'quick analyze manual fallback',source:'manual quick analyze'};$('#qr').innerHTML=(found?'<p class="good">Trovato in market.json: '+esc(t)+'</p>':'<p class="warn">Ticker non trovato in market.json: fallback manuale.</p>')+card(x)}}
function exit(){var opts=s.portfolio.map(function(p){return'<option value="'+esc(C(p.t))+'">'+esc(C(p.t))+'</option>'}).join('');shell('Exit Strategy Engine','<div class="card"><label>Titolo in crisi / da gestire<select id="exitTicker">'+opts+'</select></label><button id="buildExit">Genera strategia</button></div><div id="exitResult"></div>');$('#buildExit').onclick=function(){renderExit($('#exitTicker').value)};if(s.portfolio[0])renderExit(s.portfolio[0].t)}
