function settingsPreviewHtml(){var st=profile(),best=radarList()[0],p=best?setupPlan(best,'setup'):null;return'<div class="decision"><h3>Ricalcolo realtime</h3><p class="good">Profilo capitale salvato localmente</p><div class="grid"><div class="metric"><small>Risk amount base</small>'+eu(Number(st.tradingCapital||0)*Number(st.riskPct||0)/100)+'</div><div class="metric"><small>Target profit %</small>'+pc(st.targetProfitPct)+'</div><div class="metric"><small>Capitale trading</small>'+eu(st.tradingCapital)+'</div><div class="metric"><small>Liquidità</small>'+eu(st.freeCash)+'</div>'+(p?'<div class="metric"><small>Best max shares</small>'+p.maxShares+'</div><div class="metric"><small>Best target profit</small>'+eu(p.expectedProfit)+'</div><div class="metric"><small>Best size</small>'+eu(p.size)+'</div><div class="metric"><small>Compatibilità</small>'+p.compat+'/100 · '+esc(p.sizeRule)+'</div>':'')+'</div></div>'}function settings(){var st=Object.assign({},s.settings,profile());shell('Settings / Profile','<div class="card"><h2>Settings avanzate</h2><p class="good">Profilo capitale salvato localmente</p><div class="grid"><label>Capitale totale<input id="totalCapital" data-setting="totalCapital" type="number" value="'+esc(st.totalCapital)+'"></label><label>Liquidità disponibile<input id="freeCash" data-setting="freeCash" type="number" value="'+esc(st.freeCash)+'"></label><label>Capitale trading<input id="tradingCapital" data-setting="tradingCapital" type="number" value="'+esc(st.tradingCapital)+'"></label><label>Capitale ETF<input id="etfCapital" data-setting="etfCapital" type="number" value="'+esc(st.etfCapital)+'"></label><label>Risk per trade %<input id="risk" data-setting="riskPct" type="number" step="0.1" value="'+esc(st.riskPct)+'"></label><label>Target profit %<input id="targetProfitPct" data-setting="targetProfitPct" type="number" step="0.1" value="'+esc(st.targetProfitPct)+'"></label><label>Leva consentita<select id="leverageAllowed" data-setting="leverageAllowed"><option value="no" '+(!st.leverageAllowed?'selected':'')+'>NO</option><option value="yes" '+(st.leverageAllowed?'selected':'')+'>SI</option></select></label><label>Preferred trade duration<input id="preferredDuration" data-setting="preferredDuration" value="'+esc(st.preferredDuration)+'"></label></div><label>Modalita<input id="mode" data-setting="mode" value="'+esc(st.mode)+'"></label><label>API prezzi<input id="api" data-setting="api" value="'+esc(st.api||'')+'" placeholder="https://tuo-backend/quotes?symbols="></label><div id="settingsPreview">'+settingsPreviewHtml()+'</div><button id="saveSet">Salva settings</button></div><div class="card"><h3>Market data</h3><p>La app legge data/market.json, valida ticker reali, mostra fonte quote e blocca P/L/Exit se la fonte e invalida.</p></div>');function sync(){var k=this.getAttribute('data-setting'),v=this.value;if(k==='leverageAllowed')s.capitalProfile[k]=v==='yes';else if(['totalCapital','freeCash','etfCapital','tradingCapital','riskPct','targetProfitPct'].indexOf(k)>=0)s.capitalProfile[k]=Number(v||0);else s.settings[k]=v;save();var prev=$('#settingsPreview');if(prev)prev.innerHTML=settingsPreviewHtml()}$$('[data-setting]').forEach(function(e){e.oninput=sync;e.onchange=sync});$('#saveSet').onclick=function(){save();settings()}}

